const x = 'global';

function outer() {
  const x = 'outer';

  function inner() {
    // x is resolved based on WHERE inner is defined
    // (lexically inside outer), not where it's called
    console.log(x);
  }

  return inner;
}

const myFn = outer();

function caller() {
  const x = 'caller';
  myFn();  // What does it log?
}

caller();
// Output: 'outer'
// Even though we call myFn() inside caller() where x = 'caller',
// inner still sees x = 'outer' because that was its lexical scope.

// If JavaScript used dynamic scoping:
// The output would be 'caller' (based on call stack).
// But JavaScript uses LEXICAL scoping, so it's 'outer'.

const outer = 'global';

{
  // Block scope (lexically scoped to this block)
  const blockVar = 'block';

  {
    // Nested block scope
    const nestedVar = 'nested';
    console.log(nestedVar);  // 'nested' (own scope)
    console.log(blockVar);   // 'block' (from outer block)
    console.log(outer);      // 'global' (from global)
  }

  // console.log(nestedVar);  // ReferenceError (block-scoped)
  console.log(blockVar);     // 'block' (still in scope)
}

// console.log(blockVar);  // ReferenceError (block-scoped)

// The nesting structure of blocks determines the lexical scope,
// exactly like nested functions.

const obj = {
  name: 'MyObject',
  regularMethod: function() {
    // Regular function: 'this' depends on call site
    console.log('regular:', this.name);

    const innerRegular = function() {
      console.log('inner regular:', this.name);
      // 'this' is global/undefined (lost context)
    };

    const innerArrow = () => {
      console.log('inner arrow:', this.name);
      // Arrow: 'this' is lexically captured from regularMethod
    };

    innerRegular();  // undefined or global
    innerArrow();    // 'MyObject'
  },

  arrowMethod: () => {
    // Arrow function: 'this' is lexically from enclosing scope
    console.log('arrow method:', this.name);
    // 'this' is NOT obj — it's the global object!
  }
};

obj.regularMethod();  // Works as expected
obj.arrowMethod();    // undefined (arrow doesn't have own this)

// Arrow functions capture 'this' from the enclosing lexical scope.
// Regular functions get 'this' from the call site (dynamic).

function delayedLogger(message, delay) {
  // 'message' and 'delay' are lexically scoped to this function

  setTimeout(function() {
    // This regular function runs LATER, but still has access
    // to 'message' and 'delay' via lexical scoping
    console.log(message + ' (after ' + delay + 'ms)');
  }, delay);

  // The callback forms a CLOSURE over 'message' and 'delay'
}

delayedLogger('Hello', 1000);
// After 1 second: 'Hello (after 1000ms)'

// The callback was defined INSIDE delayedLogger, so it
// captures the lexical scope. This is WHY callbacks work!

// Even though setTimeout's callback runs in a completely
// different execution context, it still accesses the
// original 'message' and 'delay' via lexical scoping.

// JavaScript does NOT use dynamic scoping for VARIABLES
// But 'this' behaves similarly to dynamic scoping

function showThis() {
  console.log(this.name);
}

const obj1 = { name: 'Object 1', show: showThis };
const obj2 = { name: 'Object 2', show: showThis };

obj1.show();  // 'Object 1' (depends on CALL SITE — dynamic)
obj2.show();  // 'Object 2' (depends on CALL SITE — dynamic)

// This is DYNAMIC behavior — 'this' depends on how the
// function is CALLED, not where it's DEFINED.

// True lexical scope would make showThis always see the
// same 'name' regardless of how it's called.

// This is why 'this' is confusing — it's the ONE thing
// in JavaScript that is NOT lexically scoped by default.
